import os
import warnings
warnings.filterwarnings("ignore")

import requests
import csv
import base64
import time
from datetime import datetime, timedelta


TOKEN = os.getenv("GITHUB_TOKEN")
HEADERS = {"Authorization": f"token {TOKEN}"}

SEARCH_URL = "https://api.github.com/search/repositories"

languages = ["Java", "Python", "C++", "C", "C#"]

six_months_ago = (datetime.utcnow() - timedelta(days=180)).strftime("%Y-%m-%d")


def get_readme(owner, repo):
    url = f"https://api.github.com/repos/{owner}/{repo}/readme"

    try:
        r = requests.get(url, headers=HEADERS)

        if r.status_code == 200:
            content = r.json()["content"]
            return base64.b64decode(content).decode("utf-8", errors="ignore")
    except Exception as e:
        print("Error fetching README:", e)

    return ""

def get_contributors(owner, repo):

    url = f"https://api.github.com/repos/{owner}/{repo}/contributors"

    try:
        r = requests.get(
            url,
            headers=HEADERS,
            params={"per_page": 1, "anon": "true"}
        )

        if r.status_code != 200:
            return 0

        # If pagination exists
        if "Link" in r.headers:

            link_header = r.headers["Link"]

            if 'rel="last"' in link_header:
                last_page = link_header.split('rel="last"')[0].split("&page=")[-1].split(">")[0]
                return int(last_page)

        # If no pagination header → only one contributor
        return len(r.json())

    except Exception as e:
        print("Error fetching contributors:", e)
        return 0

for language in languages:

    print("Mining language:", language)

    query = f"language:{language} fork:false pushed:>={six_months_ago}"

    repositories = []

    for page in range(1,11):

        params = {
            "q": query,
            "sort": "stars",
            "order": "desc",
            "per_page": 100,
            "page": page
        }

        response = requests.get(SEARCH_URL, headers=HEADERS, params=params)

        items = response.json()["items"]

        for repo in items:
            print(f"Processing: {repo['full_name']}")

            owner = repo["owner"]["login"]
            name = repo["name"]

            collaborators = get_contributors(owner, name)

            if collaborators <= 3:
                continue

            readme = get_readme(owner,name)

            repositories.append({
                "name": name,
                "owner": owner,
                "description": repo["description"],
                "stars": repo["stargazers_count"],
                "forks": repo["forks_count"],
                "watchers": repo["watchers_count"],
                "collaborators": collaborators,
                "url": repo["html_url"],
                "last_update": repo["pushed_at"],
                "readme": readme.replace("\n"," ")
            })

            time.sleep(0.2)

    filename = f"repos/github_{language.lower().replace('+','p')}_repos.csv"

    with open(filename,"w",newline="",encoding="utf-8") as f:

        writer = csv.DictWriter(
            f,
            fieldnames=[
                "name",
                "owner",
                "description",
                "stars",
                "forks",
                "watchers",
                "collaborators",
                "url",
                "last_update",
                "readme"
            ]
        )

        writer.writeheader()
        writer.writerows(repositories)

    print("Saved:", filename, "Repos:", len(repositories))